package v1

import (
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"sync"
	"time"

	"github.com/oklog/ulid/v2"
)

// Matcher represents a label matcher for silence matching.
type Matcher struct {
	Name    string `json:"name"`
	Value   string `json:"value"`
	IsRegex bool   `json:"isRegex"`
}

// Silence represents a single silence for alerting.
type Silence struct {
	ID        string     `json:"id"`
	Matchers  []Matcher  `json:"matchers"`
	StartsAt  time.Time  `json:"startsAt"`
	EndsAt    time.Time  `json:"endsAt"`
	CreatedBy string     `json:"createdBy"`
	Comment   string     `json:"comment"`
}

// SilenceRequest represents a silence request (without ID).
type SilenceRequest struct {
	Matchers  []Matcher `json:"matchers"`
	StartsAt  time.Time `json:"startsAt"`
	EndsAt    time.Time `json:"endsAt"`
	CreatedBy string    `json:"createdBy"`
	Comment   string    `json:"comment"`
}

// SilenceStore provides in-memory storage for silences.
type SilenceStore struct {
	mu       sync.RWMutex
	silences map[string]*Silence
}

// NewSilenceStore creates a new silence store.
func NewSilenceStore() *SilenceStore {
	return &SilenceStore{
		silences: make(map[string]*Silence),
	}
}

// CreateSilence creates a new silence and returns its ID.
func (s *SilenceStore) CreateSilence(req *SilenceRequest) (string, error) {
	if err := validateSilenceRequest(req); err != nil {
		return "", err
	}

	id := ulid.Make().String()

	s.mu.Lock()
	defer s.mu.Unlock()

	s.silences[id] = &Silence{
		ID:        id,
		Matchers:  req.Matchers,
		StartsAt:  req.StartsAt,
		EndsAt:    req.EndsAt,
		CreatedBy: req.CreatedBy,
		Comment:   req.Comment,
	}

	return id, nil
}

// validateSilenceRequest validates a silence request.
func validateSilenceRequest(req *SilenceRequest) error {
	if req == nil {
		return fmt.Errorf("silence request is nil")
	}

	if len(req.Matchers) == 0 {
		return fmt.Errorf("matchers must not be empty")
	}

	for i, matcher := range req.Matchers {
		if matcher.Name == "" {
			return fmt.Errorf("matcher %d: name must not be empty", i)
		}
	}

	if req.StartsAt.IsZero() {
		return fmt.Errorf("startsAt must be set")
	}

	if req.EndsAt.IsZero() {
		return fmt.Errorf("endsAt must be set")
	}

	if req.StartsAt.After(req.EndsAt) {
		return fmt.Errorf("startsAt must be before endsAt")
	}

	return nil
}

// BulkSilenceError represents an error in bulk silence creation.
type BulkSilenceError struct {
	Index   int    `json:"index"`
	Message string `json:"message"`
}

// BulkSilenceResponse represents the response for bulk silence creation.
type BulkSilenceResponse struct {
	IDs []string `json:"ids"`
}

// silence handles POST requests for creating a single silence.
func (api *API) silence(r *http.Request) apiFuncResult {
	var req SilenceRequest
	body, err := io.ReadAll(r.Body)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error reading request body: %w", err)}, nil, nil}
	}

	if err := json.Unmarshal(body, &req); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error parsing request body: %w", err)}, nil, nil}
	}

	id, err := api.silenceStore.CreateSilence(&req)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, err}, nil, nil}
	}

	return apiFuncResult{map[string]string{"id": id}, nil, nil, nil}
}

// silenceBulk handles POST requests for creating multiple silences.
func (api *API) silenceBulk(r *http.Request) apiFuncResult {
	var requests []SilenceRequest
	body, err := io.ReadAll(r.Body)
	if err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error reading request body: %w", err)}, nil, nil}
	}

	if err := json.Unmarshal(body, &requests); err != nil {
		return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("error parsing request body: %w", err)}, nil, nil}
	}

	if len(requests) == 0 {
		return apiFuncResult{&BulkSilenceResponse{IDs: []string{}}, nil, nil, nil}
	}

	// Validate all silences before creating any
	for i, req := range requests {
		if err := validateSilenceRequest(&req); err != nil {
			return apiFuncResult{nil, &apiError{errorBadData, fmt.Errorf("silence %d: %w", i, err)}, &BulkSilenceError{Index: i, Message: err.Error()}, nil}
		}
	}

	// Create all silences
	ids := make([]string, 0, len(requests))
	for _, req := range requests {
		id, err := api.silenceStore.CreateSilence(&req)
		if err != nil {
			// This should not happen since we validated above
			return apiFuncResult{nil, &apiError{errorInternal, err}, nil, nil}
		}
		ids = append(ids, id)
	}

	return apiFuncResult{&BulkSilenceResponse{IDs: ids}, nil, nil, nil}
}

