func TestSilenceBulkAtomicity(t *testing.T) {
	api := &API{
		silenceStore: NewSilenceStore(),
		ready:        func(f http.HandlerFunc) http.HandlerFunc { return f },
	}

	now := time.Now()
	startTime := now.Add(1 * time.Hour)
	endTime := now.Add(2 * time.Hour)

	// Create 2 valid silences and 1 invalid
	requests := []SilenceRequest{
		{
			Matchers: []Matcher{
				{Name: "alertname", Value: "TestAlert1", IsRegex: false},
			},
			StartsAt:  startTime,
			EndsAt:    endTime,
			CreatedBy: "test-user",
			Comment:   "Test silence 1",
		},
		{
			Matchers: []Matcher{
				{Name: "alertname", Value: "TestAlert2", IsRegex: false},
			},
			StartsAt:  startTime,
			EndsAt:    endTime,
			CreatedBy: "test-user",
			Comment:   "Test silence 2",
		},
		{
			Matchers:  []Matcher{}, // Invalid
			StartsAt:  startTime,
			EndsAt:    endTime,
			CreatedBy: "test-user",
			Comment:   "Test silence 3",
		},
	}

	body, err := json.Marshal(requests)
	require.NoError(t, err)

	r := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))

	// Before the request, the store should be empty
	api.silenceStore.mu.RLock()
	beforeCount := len(api.silenceStore.silences)
	api.silenceStore.mu.RUnlock()
	require.Equal(t, 0, beforeCount)

	result := api.silenceBulk(r)

	// The request should fail due to the third silence
	require.NotNil(t, result.err)

	// After the failed request, the store should still be empty (atomicity)
	api.silenceStore.mu.RLock()
	afterCount := len(api.silenceStore.silences)
	api.silenceStore.mu.RUnlock()
	require.Equal(t, 0, afterCount)
}

